r = "<tr><td>&nbsp;</td>";}else{	$echostr = "<tr><td><img src=";	if ($dbcheck)	{//		$echostr .=('"../pics/vinkje0.gif" alt=""');		$echostr .=('"../pics/grijs.gif" alt=""');	}else{//		$echostr .=('"../pics/vinkje1.gif" alt="Vinkje"');		$echostr .=('"../pics/grijs.gif" alt="Vinkje"');	}	$echostr .= "border=\"0\"></td>";}$echostr .= "<td valign=\"top\" align=\"right\"><a href=\"".$de_url.".php\" target=\"_self\" ";if ($menuitem==$hiero1 || $menuitem==$hiero2){ 	$echostr .= "class=\"menubtnhiero\" "; }else{	$echostr .= "class=\"menubutton\" "; } $echostr .= " onMouseOver=\"document.hellup.tkst.value='$uitleg'; return true;\" onMouseOut=\"document.hellup.tkst.value='';\">";$echostr .= "$menuitem</a></td></tr>\n";return $echostr;}function XXhelppagina(){$helpurl = $_SERVER['PHP_SELF']; $helpurl = substr($helpurl, 0, strlen($helpurl)-4);$helpurl =  $helpurl."_hlp.php";///echo $helpurl;if(file_exists($helpurl)){ 	//$kaartenbak=file("$kaartenmap/$naam$ID.txt");	echo "<tr><td>&nbsp;</td><td valign=\"top\" align=\"right\"><a href=\"".$helpurl."\" target=\"_self\"  class=\"menubutton\">deze pag.</a></td></tr>\n";}}function helppagina($hierorichting){$helpurl = str_replace($hierorichting,'',$_SERVER['PHP_SELF']); // remove the string $hierorichting from the URL $helpurl = substr($helpurl, 0, strlen($helpurl)-4);$helpurl =  $helpurl."_hlp.php";///echo $helpurl;if(file_exists($helpurl)){ 	//$kaartenbak=file("$kaartenmap/$naam$ID.txt");	echo "<tr><td>&nbsp;</td><td valign=\"top\" align=\"right\"><a href=\"".$helpurl."\" target=\"_self\" class=\"menubutton\" onMouseOver=\"document.hellup.tkst.value='info over het gebruik van deze pagina'; return true;\" onMouseOut=\"document.hellup.tkst.value='';\" >deze pag.</a></td></tr>\n";}}///functies voor layoutfunction is_even($getal){    return ( $getal & 1 == 1 ) ? false : true;}////functies vooe verzendenfunction zoeknummer(){	return strtotime("now").rand(1000,9999);}functio